// 获取 WASM 内存引用
const memory: WebAssembly.Memory = wasmInstance.memory;

// 获取 Rust Vec<u8> 在 WASM 内存中的指针
const ptr: number = pathfinder.dynamic_bitmap_ptr();
const byteSize: number = pathfinder.bitmap_byte_size();

// 创建指向 WASM 内存的 TypedArray 视图
const view = new Uint8Array(memory.buffer, ptr, byteSize);

// JS 写入 → Rust 读取，零拷贝！
view[0] = 0xFF;

// 设置格子 (x, y) 为障碍物
const idx = y * mapWidth + x;
stagingBuffer[idx >> 3] |= 1 << (idx & 7);
// idx >> 3  = 字节索引（除以 8）
// idx & 7   = bit 位移（模 8）

// 清除格子 (x, y) 的障碍物
stagingBuffer[idx >> 3] &= ~(1 << (idx & 7));

